import logging

# Configure logging
logging.basicConfig(level=logging.INFO)


def process(data):
    if not isinstance(data, dict):
        logging.warning("Input data is not a dictionary.")
        return

    value = data.get("value")
    if value is None:
        logging.warning("'value' key is missing in the input data.")
        return

    if value > 0:
        logging.info("Valid")
    else:
        logging.info("Invalid")


